PROCEDURE HandleInterrupt
BEGIN
    // 1. CPU receives INTR signal
    IF CPU.InterruptEnabled AND CPU.ReceivedInterrupt() THEN
        // 2. Complete current instruction
        CPU.CompleteCurrentInstruction()

        // 3. Save processor state
        PUSH CPU.ProgramCounter
        PUSH CPU.StatusRegister
        PUSH CPU.GeneralPurposeRegisters

        // 4. Acknowledge interrupt
        CPU.SendSignal(INTA)
        interruptVector = CPU.ReadFromBus()

        // 5. Get ISR address from vector table
        isrAddress = Memory.Read(interruptVector * 4)

        // 6. Jump to ISR
        CPU.ProgramCounter = isrAddress

        // 7. Execute ISR (omitted for brevity)
        // ... handle interrupt-specific task ...

        // 8. Return from interrupt
        POP CPU.GeneralPurposeRegisters
        POP CPU.StatusRegister
        POP CPU.ProgramCounter
    END IF
END

#include <stdint.h>

// Function pointer type for interrupt handlers
typedef void (*ISR_Handler)(void);

// Interrupt Vector Table (typical ARM Cortex-M style)
typedef struct {
    uint32_t* stack_initial;
    ISR_Handler Reset;
    ISR_Handler NMI_Handler;
    ISR_Handler HardFault_Handler;
    ISR_Handler MemManage_Handler;
    ISR_Handler BusFault_Handler;
    ISR_Handler UsageFault_Handler;
    // ... more handlers ...
} VectorTable_t;

// External linker symbols for vector table location
extern uint32_t _estack;
extern uint32_t _sidata;

// Weak attribute allows user override
extern void Default_Handler(void) __attribute__((weak));

// Vector table placed in .isr_vector section
__attribute__((section(".isr_vector")))
VectorTable_t VectorTable = {
    .stack_initial = &_estack,
    .Reset = Reset_Handler,
    .NMI_Handler = NMI_Handler,
    .HardFault_Handler = HardFault_Handler,
    .MemManage_Handler = MemManage_Handler,
    .BusFault_Handler = BusFault_Handler,
    .UsageFault_Handler = UsageFault_Handler,
};

