// Function to enable specific interrupt
void Enable_IRQ(uint8_t irq_num) {
    if (irq_num >= 0 && irq_num < 32) {
        NVIC->ISER[irq_num / 32] = (1 << (irq_num % 32));
    }
}

// Function to set priority of interrupt
void Set_IRQ_Priority(uint8_t irq_num, uint8_t priority) {
    if (irq_num >= 0 && irq_num < 32) {
        NVIC->IP[irq_num] = priority << 4;  // 4 bits for priority
    }
}

// APPROACH 1: POLLING
PROCEDURE PollDevices
BEGIN
    WHILE system_running DO
        // Check each device in sequence
        FOR EACH device IN device_list DO
            IF device.HasData() THEN
                data = device.ReadData()
                ProcessData(data)
            END IF
        END FOR

        // CPU is busy checking even when no data
        // Cannot do other useful work
    END WHILE
END

// APPROACH 2: INTERRUPT-DRIVEN
PROCEDURE MainProgram
BEGIN
    EnableInterrupts()

    WHILE system_running DO
        // Do useful work when no interrupts
        ProcessBackgroundTasks()
        UpdateDisplay()
        CheckUserInput()
    END WHILE
END

PROCEDURE DeviceInterruptHandler
BEGIN
    // This runs only when device needs attention
    SaveState()

    data = device.ReadData()
    ProcessData(data)

    ClearDeviceInterrupt()
    RestoreState()
    ReturnFromInterrupt()
END

